import{_ as e,o as i,c as a,a2 as o}from"./chunks/framework.D36jym0Z.js";const c=JSON.parse('{"title":"What is LightMem2","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/what-is-lightmem2.md","filePath":"getting-started/what-is-lightmem2.md","lastUpdated":1784542960000}'),n={name:"getting-started/what-is-lightmem2.md"};function s(l,t,r,h,g,d){return i(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="what-is-lightmem2" tabindex="-1">What is LightMem2 <a class="header-anchor" href="#what-is-lightmem2" aria-label="Permalink to &quot;What is LightMem2&quot;">​</a></h1><p>LightMem2 is an <strong>open plugin platform for long-running AI agents</strong>. It lets you build agent capabilities once and run them across multiple agent hosts — OpenClaw, Codex, Claude Code, and future hosts.</p><h2 id="lightmem2-vs-tokenpilot" tabindex="-1">LightMem2 vs. TokenPilot <a class="header-anchor" href="#lightmem2-vs-tokenpilot" aria-label="Permalink to &quot;LightMem2 vs. TokenPilot&quot;">​</a></h2><p>A common point of confusion: LightMem2 and TokenPilot are not the same thing.</p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">LightMem2</th><th style="text-align:left;">TokenPilot</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>What it is</strong></td><td style="text-align:left;">A plugin platform and runtime</td><td style="text-align:left;">A plugin that runs on LightMem2</td></tr><tr><td style="text-align:left;"><strong>Role</strong></td><td style="text-align:left;">Loads, manages, and executes plugins</td><td style="text-align:left;">Provides cache-aware context management</td></tr><tr><td style="text-align:left;"><strong>Scope</strong></td><td style="text-align:left;">Platform-wide: plugins, adapters, CLI</td><td style="text-align:left;">One specific capability: reducing token usage</td></tr><tr><td style="text-align:left;"><strong>Status</strong></td><td style="text-align:left;">Active development</td><td style="text-align:left;">Stable — the first official plugin</td></tr></tbody></table><p>Think of LightMem2 as the operating system and TokenPilot as an app that runs on it.</p><h2 id="what-problems-it-solves" tabindex="-1">What Problems It Solves <a class="header-anchor" href="#what-problems-it-solves" aria-label="Permalink to &quot;What Problems It Solves&quot;">​</a></h2><ul><li><strong>Long sessions get expensive</strong>. As agent sessions grow, every turn carries more context, which means more tokens and higher costs.</li><li><strong>Context is repetitive</strong>. Much of what gets sent to the model each turn is identical to the previous turn — wasteful if not cached.</li><li><strong>Tool output is noisy</strong>. Large tool responses can pollute future turns with irrelevant data.</li><li><strong>Sessions don&#39;t prune themselves</strong>. Without eviction, old context accumulates until sessions hit limits or become too slow.</li></ul><p>LightMem2 addresses these through its plugin model. TokenPilot, the first plugin, implements the runtime policies: stable-prefix rewriting, context reduction, and lifecycle-aware eviction.</p><h2 id="what-it-doesn-t-solve" tabindex="-1">What It Doesn&#39;t Solve <a class="header-anchor" href="#what-it-doesn-t-solve" aria-label="Permalink to &quot;What It Doesn&#39;t Solve&quot;">​</a></h2><ul><li><strong>Short, single-turn interactions</strong>. If your sessions are always one-shot, there is nothing for caching or eviction to optimize.</li><li><strong>Model quality or accuracy</strong>. LightMem2 doesn&#39;t change model behavior — it changes what context gets sent to the model.</li><li><strong>All memory problems</strong>. Long-term memory is an experimental feature area; TokenPilot focuses on the current session&#39;s context window.</li></ul><h2 id="relationship-to-the-paper" tabindex="-1">Relationship to the Paper <a class="header-anchor" href="#relationship-to-the-paper" aria-label="Permalink to &quot;Relationship to the Paper&quot;">​</a></h2><p>The <a href="https://arxiv.org/abs/2606.17016" target="_blank" rel="noreferrer">TokenPilot paper</a> describes the cache-efficient context management technique. LightMem2 is the platform that hosts TokenPilot as its first plugin, and will host additional plugins in the future.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/LightMem2/getting-started/quick-start">Quick Start</a> — get running in under 5 minutes</li><li><a href="/LightMem2/platform-concepts/core-runtime">Core Concepts</a> — understand the platform architecture</li><li><a href="/LightMem2/plugin-catalog/tokenpilot/overview">TokenPilot Overview</a> — dive into the featured plugin</li></ul>',15)])])}const u=e(n,[["render",s]]);export{c as __pageData,u as default};
